oft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":976,"end_index":1109,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/overview?view=foundry-classic","start_index":1286,"end_index":1398,"title":"What is Foundry Agent Service? - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":1649,"end_index":1782,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/bing-grounding?view=foundry-classic","start_index":1860,"end_index":1999,"title":"How to use Grounding with Bing Search in Foundry Agent Service ..."},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/bing-custom-search?view=foundry-classic","start_index":2093,"end_index":2236,"title":"How to use Custom Bing Search with Foundry Agent Service - Azure OpenAI ..."},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":2472,"end_index":2605,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/overview?view=foundry-classic","start_index":2857,"end_index":2969,"title":"What is Foundry Agent Service? - Microsoft Foundry"}],"logprobs":[]}],"status":"completed"}],"parallel_tool_calls":true,"presence_penalty":0.0,"previous_response_id":null,"prompt_cache_key":null,"prompt_cache_retention":null,"reasoning":{"effort":"none","summary":null},"safety_identifier":null,"service_tier":"default","store":true